C++Blueprint <pre><code>void UGuildChatWidget::Initialize()
{
    auto* ChatIntegration =
        GetOwningPlayerController()
            -&gt;FindComponentByClass&lt;UFWGuildChatIntegrationComponent&gt;();

    if (ChatIntegration &amp;&amp; ChatIntegration-&gt;IsChatSystemAvailable())
    {
        ChatIntegration-&gt;OnGuildChatMessageReceived.AddDynamic(
            this, &amp;UGuildChatWidget::OnMessageReceived);
        SetVisibility(ESlateVisibility::Visible);
    }
    else
    {
        SetVisibility(ESlateVisibility::Collapsed);
    }
}

void UGuildChatWidget::OnSendButtonClicked()
{
    auto* ChatIntegration =
        GetOwningPlayerController()
            -&gt;FindComponentByClass&lt;UFWGuildChatIntegrationComponent&gt;();

    if (ChatIntegration)
    {
        ChatIntegration-&gt;SendGuildMessage(MessageInputBox-&gt;GetText().ToString());
        MessageInputBox-&gt;SetText(FText::GetEmpty());
    }
}
</code></pre> <ol> <li>Add FW Guild Chat Integration Component to the same actor as your guild components.</li> <li>On your chat widget, call Is Chat System Available to decide whether to show the guild chat tab.</li> <li>Bind On Guild Chat Message Received to append messages to your chat log.</li> <li>Wire a send button to call Send Guild Message with the text input value.</li> </ol>

C++Blueprint <pre><code>void AMyPlayerController::BeginPlay()
{
    Super::BeginPlay();

    GuildManager = FindComponentByClass&lt;UFWGuildManagerComponent&gt;();
    if (GuildManager)
    {
        GuildManager-&gt;OnGuildCreated.AddDynamic(
            this, &amp;AMyPlayerController::HandleGuildCreated);
        GuildManager-&gt;OnGuildOperationFailed.AddDynamic(
            this, &amp;AMyPlayerController::HandleGuildError);
    }
}

void AMyPlayerController::HandleGuildCreated(
    EFWGuildOperationResult Result, const FFWGuildDetails&amp; Details)
{
    if (Result == EFWGuildOperationResult::Success)
    {
        UE_LOG(LogGuild, Log, TEXT("Guild '%s' created with %d ranks."),
            *Details.Info.Name, Details.Ranks.Num());
    }
}

void AMyPlayerController::HandleGuildError(
    EFWGuildOperationResult Result, const FString&amp; Message)
{
    UE_LOG(LogGuild, Warning, TEXT("Guild operation failed: %s"), *Message);
}
</code></pre> <ol> <li>Add a FW Guild Manager Component to your Player Controller.</li> <li>In the Event Graph, drag from the component and select Bind Event to On Guild Created.</li> <li>In the bound event, check the Result enum for <code>Success</code> before accessing guild details.</li> <li>Call Create Guild with a name and description to trigger the flow.</li> </ol>

C++Blueprint <pre><code>void UGuildRosterWidget::RefreshRoster()
{
    UFWGuildStateComponent* GuildState =
        GetOwningPlayerController()-&gt;FindComponentByClass&lt;UFWGuildStateComponent&gt;();

    if (!GuildState || !GuildState-&gt;IsInGuild())
    {
        ShowNoGuildMessage();
        return;
    }

    const TArray&lt;FFWGuildMember&gt;&amp; Members = GuildState-&gt;GetMembers();
    for (const FFWGuildMember&amp; Member : Members)
    {
        AddMemberRow(Member.DisplayName, Member.Rank.Name, Member.bIsOnline);
    }

    SetGuildName(GuildState-&gt;GetGuildInfo().Name);
    SetMemberCountText(FString::Printf(TEXT("%d / %d online"),
        GuildState-&gt;GetOnlineMemberCount(),
        GuildState-&gt;GetMemberCount()));
}
</code></pre> <ol> <li>Get a reference to the FW Guild State Component on your Player Controller.</li> <li>Call Is In Guild to check membership.</li> <li>Use Get Members to populate a roster list widget.</li> <li>Bind On Guild State Changed to automatically refresh the UI when data changes.</li> </ol>

