C++Blueprint <pre><code>void UCraftingWidget::OnCraftButtonClicked()
{
    UFWCraftingComponent* Crafting =
        GetOwningPlayerPawn()-&gt;FindComponentByClass&lt;UFWCraftingComponent&gt;();

    if (Crafting &amp;&amp; SelectedRecipe)
    {
        if (Crafting-&gt;CanCraft(SelectedRecipe, CraftQuantity))
        {
            Crafting-&gt;CraftItem(SelectedRecipe, CraftQuantity);
        }
    }
}

void UCraftingWidget::RefreshRecipeList()
{
    UFWCraftingComponent* Crafting =
        GetOwningPlayerPawn()-&gt;FindComponentByClass&lt;UFWCraftingComponent&gt;();

    RecipeListView-&gt;ClearListItems();
    TArray&lt;UFWRecipeDefinition*&gt; Recipes = Crafting-&gt;GetLearnedRecipes();

    for (UFWRecipeDefinition* Recipe : Recipes)
    {
        URecipeEntry* Entry = CreateWidget&lt;URecipeEntry&gt;(
            this, RecipeEntryClass);
        Entry-&gt;SetRecipe(Recipe);
        Entry-&gt;SetCanCraft(Crafting-&gt;CanCraft(Recipe));
        RecipeListView-&gt;AddItem(Entry);
    }
}
</code></pre> <ol> <li>Add FW Crafting Component to your character.</li> <li>Set the Recipe Database property to your recipe database asset.</li> <li>Call Get Learned Recipes to populate a recipe list widget.</li> <li>Use Can Craft to grey out unavailable recipes.</li> <li>Wire a craft button to call Craft Item with the selected recipe.</li> <li>Bind On Crafting Completed to show the crafted item result.</li> </ol>

C++Blueprint <pre><code>void AMyCharacter::BeginPlay()
{
    Super::BeginPlay();

    Equipment-&gt;OnItemEquipped.AddDynamic(
        this, &amp;AMyCharacter::HandleItemEquipped);
    Equipment-&gt;OnSetBonusActivated.AddDynamic(
        this, &amp;AMyCharacter::HandleSetBonusActivated);
}

void AMyCharacter::HandleItemEquipped(
    EFWEquipmentType Slot, const FFWItemInstance&amp; Item)
{
    UE_LOG(LogInventory, Log, TEXT("Equipped '%s' in slot %s"),
        *Item.Definition-&gt;DisplayName.ToString(),
        *UEnum::GetValueAsString(Slot));

    // Update character mesh/visuals
    UpdateEquipmentVisuals(Slot, Item);
}

void AMyCharacter::HandleSetBonusActivated(
    const UFWItemSetDefinition* SetDef, int32 PieceCount)
{
    UE_LOG(LogInventory, Log, TEXT("Set bonus '%s' activated at %d pieces"),
        *SetDef-&gt;SetName.ToString(), PieceCount);
}
</code></pre> <ol> <li>Add FW Equipment Component to your character.</li> <li>Bind On Item Equipped to update your character's visual mesh.</li> <li>Bind On Equipment Stats Changed to refresh the stat display UI.</li> <li>Use Get Total Stat Value with a gameplay tag to read current equipment stats.</li> </ol>

C++Blueprint <pre><code>void AMyCharacter::PickupItem(AActor* ItemActor)
{
    AWorldItem* WorldItem = Cast&lt;AWorldItem&gt;(ItemActor);
    if (!WorldItem) return;

    FFWItemInstance NewItem;
    NewItem.InstanceId = FGuid::NewGuid();
    NewItem.Definition = WorldItem-&gt;GetItemDefinition();
    NewItem.Quantity = WorldItem-&gt;GetQuantity();

    if (Inventory-&gt;AddItem(NewItem))
    {
        WorldItem-&gt;Destroy();
    }
    else
    {
        // Inventory full notification is handled by OnInventoryFull delegate
    }
}
</code></pre> <ol> <li>Add FW Inventory Component to your character.</li> <li>Create an <code>FFWItemInstance</code> struct with the item definition and quantity.</li> <li>Call Add Item on the inventory component.</li> <li>Bind On Inventory Full to show a "bags full" notification.</li> </ol>

C++Blueprint <pre><code>void AMyNPCVendor::BeginPlay()
{
    Super::BeginPlay();

    VendorComp = FindComponentByClass&lt;UFWVendorComponent&gt;();
    VendorComp-&gt;BuyPriceMultiplier = 1.2f;    // 20% markup
    VendorComp-&gt;SellPriceMultiplier = 0.30f;   // 30% return
    VendorComp-&gt;MaxBuybackSlots = 8;
}

void AMyNPCVendor::OnPlayerInteract(AMyCharacter* Player)
{
    UFWInventoryComponent* PlayerInventory =
        Player-&gt;FindComponentByClass&lt;UFWInventoryComponent&gt;();

    // Open vendor UI with vendor and player inventory references
    UVendorWidget* Widget = CreateWidget&lt;UVendorWidget&gt;(
        Player-&gt;GetController&lt;APlayerController&gt;(), VendorWidgetClass);
    Widget-&gt;Initialize(VendorComp, PlayerInventory);
    Widget-&gt;AddToViewport();
}
</code></pre> <ol> <li>Add FW Vendor Component to your NPC actor.</li> <li>In the Details panel, add item definitions to the Stock Definitions array.</li> <li>Set Buy Price Multiplier and Sell Price Multiplier as desired.</li> <li>On player interaction, open a vendor UI widget that references the vendor component.</li> <li>Bind On Transaction Failed to show error messages.</li> </ol>

